class Solution:
    def countSteppingNumbers(self, low: str, high: str) -> int:
        MOD = 10**9 + 7

        def countSteppingNumbersUpTo(s: str) -> int:
            n = len(s)
            dp = [[[0] * 10 for _ in range(2)] for _ in range(n + 1)]
            dp[0][0][0] = 1

            for i in range(1, n + 1):
                for tight in range(2):
                    for prev in range(10):
                        if dp[i - 1][tight][prev] == 0:
                            continue
                        max_digit = int(s[i - 1]) if tight else 9
                        for d in range(0, max_digit + 1):
                            new_tight = tight and (d == max_digit)
                            if prev == 0 and d == 0:
                                continue
                            if prev == 0 and d != 0:
                                dp[i][new_tight][d] = (dp[i][new_tight][d] + dp[i - 1][tight][prev]) % MOD
                            else:
                                if abs(d - prev) == 1:
                                    dp[i][new_tight][d] = (dp[i][new_tight][d] + dp[i - 1][tight][prev]) % MOD
            total = 0
            for tight in range(2):
                for d in range(10):
                    total = (total + dp[n][tight][d]) % MOD
            return total

        def countSteppingNumbersLessThan(s: str) -> int:
            n = len(s)
            dp = [[[0] * 10 for _ in range(2)] for _ in range(n + 1)]
            dp[0][0][0] = 1

            for i in range(1, n + 1):
                for tight in range(2):
                    for prev in range(10):
                        if dp[i - 1][tight][prev] == 0:
                            continue
                        max_digit = int(s[i - 1]) if tight else 9
                        for d in range(0, max_digit):
                            new_tight = tight and (d == max_digit)
                            if prev == 0 and d == 0:
                                continue
                            if prev == 0 and d != 0:
                                dp[i][new_tight][d] = (dp[i][new_tight][d] + dp[i - 1][tight][prev]) % MOD
                            else:
                                if abs(d - prev) == 1:
                                    dp[i][new_tight][d] = (dp[i][new_tight][d] + dp[i - 1][tight][prev]) % MOD
            total = 0
            for tight in range(2):
                for d in range(10):
                    total = (total + dp[n][tight][d]) % MOD
            return total

        def countSteppingNumbersBetween(low: str, high: str) -> int:
            return (countSteppingNumbersUpTo(high) - countSteppingNumbersLessThan(low) + MOD) % MOD

        return countSteppingNumbersBetween(low, high)
